package org.eclipse.rdf4j.sail.lmdb.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.common.iteration.CloseableIteration;
import org.eclipse.rdf4j.common.iteration.CloseableIteratorIteration;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.sail.lmdb.estimation.QuadProbe;
import org.eclipse.rdf4j.sail.lmdb.estimation.QuadValueHash;
import org.junit.jupiter.api.Test;

class SketchBasedJoinEstimatorLifecycleTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI PREDICATE = VF.createIRI("urn:predicate");

	@Test
	void legacyStrategyNamesNormalizeToOneRuntimeStrategy() {
		for (String name : List.of("omni", "fastagms", "countmin", "countmin-dual", "tuple", "joinsketch")) {
			assertEquals(SketchBasedJoinEstimator.SketchStrategy.UNIFIED,
					SketchBasedJoinEstimator.SketchStrategy.fromConfigValue(name, null));
		}
	}

	@Test
	void facadeDelegatesLifecycleToBoundedSynopsis() {
		MutableStatementSource source = new MutableStatementSource();
		Statement first = statement("s1", 1);
		Statement second = statement("s2", 2);
		source.statements.addAll(List.of(first, second));
		SketchBasedJoinEstimator.Config config = SketchBasedJoinEstimator.Config.defaults()
				.withMemoryBudgetBytes(4L * 1024L * 1024L)
				.withColdSynopsisCapacity(64)
				.withEvidenceMode("snapshot-only");

		try (SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(source, config)) {
			estimator.rebuild();
			assertTrue(estimator.isReadyNonBlocking());
			assertFalse(estimator.adaptiveEvidenceAllowed());
			assertEquals(2.0d, predicateRows(estimator));

			Statement third = statement("s3", 3);
			source.statements.add(third);
			estimator.addStatement(third);
			assertEquals(3.0d, predicateRows(estimator));

			source.statements.remove(first);
			estimator.deleteStatement(first);
			assertFalse(estimator.isReadyNonBlocking());
			assertTrue(estimator.forceFlush());
			assertEquals(2.0d, predicateRows(estimator));
			assertTrue(estimator.allocatedBytes() <= 4L * 1024L * 1024L);
		}
	}

	private static Statement statement(String subject, int value) {
		return VF.createStatement(VF.createIRI("urn:" + subject), PREDICATE, VF.createLiteral(value));
	}

	private static double predicateRows(SketchBasedJoinEstimator estimator) {
		QuadProbe probe = new QuadProbe(QuadProbe.PREDICATE, QuadProbe.OBJECT, 0L,
				QuadValueHash.hash(PREDICATE), 0L, 0L, estimator.quadSnapshotIdentity());
		return estimator.synopsisService().probe(probe).rows().estimate();
	}

	private static final class MutableStatementSource implements SketchStatementSource {
		private final List<Statement> statements = new ArrayList<>();

		@Override
		public CloseableIteration<? extends Statement> getStatements(Resource subject, IRI predicate, Value object,
				Resource... contexts) {
			return new CloseableIteratorIteration<>(statements.iterator());
		}
	}
}
